import{_ as a,o as r,c as o,a2 as t}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"ADR-0004: 接口契约 — Python API 是契约，CLI 与 serve 都是薄壳","description":"","frontmatter":{},"headers":[],"relativePath":"adr/0004-api-contract-thin-shells.md","filePath":"adr/0004-api-contract-thin-shells.md","lastUpdated":1784633569000}'),n={name:"adr/0004-api-contract-thin-shells.md"};function l(i,e,s,d,c,h){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-0004-接口契约-—-python-api-是契约-cli-与-serve-都是薄壳" tabindex="-1">ADR-0004: 接口契约 — Python API 是契约，CLI 与 serve 都是薄壳 <a class="header-anchor" href="#adr-0004-接口契约-—-python-api-是契约-cli-与-serve-都是薄壳" aria-label="Permalink to &quot;ADR-0004: 接口契约 — Python API 是契约，CLI 与 serve 都是薄壳&quot;">​</a></h1><ul><li><strong>状态</strong>：Proposed（2026-07-21，随 PR 评审定稿；CLI 部分为对 <a href="https://github.com/XnneHangLab/wikimem/pull/12" target="_blank" rel="noreferrer">#12</a> 既成事实的追认）</li><li><strong>日期</strong>：2026-07-21</li><li><strong>关联</strong>：<a href="https://github.com/XnneHangLab/XnneHangLab/blob/dev/docs/adr/0001-llm-mode-memory.md" target="_blank" rel="noreferrer">XnneHangLab ADR-0001</a>（零依赖 CLI 清单来源）、XnneHangLab ADR-0004（宿主消费方式）、<code>docs/reference/api.md</code></li></ul><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>wikimem 已有两类消费者，将有第三类：</p><ol><li><strong>宿主进程内 import</strong>（XnneHangLab 插件）：毫秒级，对比 memu-cli 子进程 2.1–2.4 s/call 的路线（XnneHangLab ADR-0003）。</li><li><strong>CLI</strong>（#12 已落地）：<code>ls / show / grep / explain / graph</code>，stdlib 实现。</li><li><strong>进程外消费者</strong>（将来）：记忆浏览工具、其他应用、宿主之外的前端——需要一个数据接口而不是命令行。yutto 的 serve/RPC 改造是先例：不执著于 CLI，在数据接口上让应用层套自己的壳。</li></ol><p>需要明确：谁是契约，谁是壳；传输协议怎么定。</p><h2 id="决策" tabindex="-1">决策 <a class="header-anchor" href="#决策" aria-label="Permalink to &quot;决策&quot;">​</a></h2><h3 id="_1-契约-python-api" tabindex="-1">1. 契约 = Python API <a class="header-anchor" href="#_1-契约-python-api" aria-label="Permalink to &quot;1. 契约 = Python API&quot;">​</a></h3><p><code>MemoryStore</code> / <code>MemoryIndex</code> / <code>Journal</code>（以及 ADR-0001 落地后的 Diary API）。语义、参数、返回结构以 <code>docs/reference/api.md</code> 为准；破坏性变更走语义化版本。</p><h3 id="_2-cli-与-serve-都是薄壳" tabindex="-1">2. CLI 与 serve 都是薄壳 <a class="header-anchor" href="#_2-cli-与-serve-都是薄壳" aria-label="Permalink to &quot;2. CLI 与 serve 都是薄壳&quot;">​</a></h3><p>同一套 API 外面的两层皮。<strong>壳内不允许业务逻辑</strong>——不在壳里加检索规则、不在壳里分叉融合参数默认值；壳只做参数转换与输出格式化。CLI 已按此形态落地（#12）；serve 照此新增。</p><h3 id="_3-serve-http-json-serve-extra" tabindex="-1">3. serve：HTTP + JSON，<code>[serve]</code> extra <a class="header-anchor" href="#_3-serve-http-json-serve-extra" aria-label="Permalink to &quot;3. serve：HTTP + JSON，`[serve]` extra&quot;">​</a></h3><ul><li>端点与 API 方法一一对应，外加 <code>/version</code>。</li><li><strong>不自研协议</strong>：HTTP + JSON + 语义化版本号，够了。</li><li>依赖归 <code>[serve]</code> extra（与 <code>[embed]</code> 同一模式），核心零依赖不破；实现期在 stdlib <code>http.server</code> 与轻量框架之间取舍。</li><li>默认绑定 <code>127.0.0.1</code>、无鉴权——面向本机进程外消费者；文档言明不要公网裸奔。</li></ul><h3 id="_4-宿主不走-serve" tabindex="-1">4. 宿主不走 serve <a class="header-anchor" href="#_4-宿主不走-serve" aria-label="Permalink to &quot;4. 宿主不走 serve&quot;">​</a></h3><p>XnneHangLab 继续进程内 import。serve 面向<strong>进程外</strong>第三方，不是宿主链路的一环——宿主前端的可视化路由由宿主自己的 FastAPI/WebSocket 提供（见 XnneHangLab ADR-0004）。</p><h3 id="_5-ui-永不进框架" tabindex="-1">5. UI 永不进框架 <a class="header-anchor" href="#_5-ui-永不进框架" aria-label="Permalink to &quot;5. UI 永不进框架&quot;">​</a></h3><p>框架的责任止于<strong>数据可及</strong>：列日期、读条目、检索、journal tail 都是 API 方法（因而自动是 CLI 子命令和 serve 端点）。界面长什么样是应用的事。file-first 还附赠一条：markdown 真相意味着 Obsidian / 任意编辑器天然是能用的&quot;记忆浏览器&quot;，debug 场景直接够用。</p><h2 id="理由" tabindex="-1">理由 <a class="header-anchor" href="#理由" aria-label="Permalink to &quot;理由&quot;">​</a></h2><ul><li>单一契约消除三类消费者之间的行为漂移——壳里无逻辑，就没有&quot;CLI 结果和 API 结果不一样&quot;这种 bug 类别。</li><li>HTTP + JSON 是所有语言、所有前端的最大公约数；自研协议在这个规模上只有成本没有收益。</li><li>serve 做成 extra 延续了&quot;能力渐进增强、核心零依赖&quot;的既有模式（<code>[embed]</code>、<code>[zh]</code>）。</li></ul><h2 id="后果" tabindex="-1">后果 <a class="header-anchor" href="#后果" aria-label="Permalink to &quot;后果&quot;">​</a></h2><p><strong>正面</strong></p><ul><li>应用层套壳有了稳定的地基；换前端、加工具不动框架。</li><li>三个表面（API / CLI / serve）共享同一套测试对象。</li></ul><p><strong>负面 / 代价</strong></p><ul><li>serve 的安全面需要文档与默认值兜底（本机绑定、无鉴权的边界说清楚）。</li><li>API 一旦宣布为契约，公开方法的签名变更成本上升——这是目的，也是代价。</li></ul><p><strong>实施</strong></p><p>serve 作为独立里程碑（建议 M6）：端点映射 → <code>/version</code> → 文档（reference 增 serve 页）→ 集成测试。</p>',26)])])}const g=a(n,[["render",l]]);export{u as __pageData,g as default};
